export function mergeSkillCatalogIntoLocales(locales: Record<string, Record<string, unknown>>): void {
  for (const locale of Object.keys(SKILL_CATALOG_I18N)) {
    const pack = SKILL_CATALOG_I18N[locale];
    if (!pack || !locales[locale]) continue;
    const game = locales[locale].game as Record<string, unknown> | undefined;
    if (!game) continue;
    const skills = (game.skills as Record<string, unknown>) || (game.skills = {});
    Object.assign(skills, { names: { ...(skills.names as object), ...pack.names }, desc: { ...(skills.desc as object), ...pack.desc } });
  }
}

export function skillSlugFromKey(skillKey: string): string {
  return skillKey.replace(/[^a-zA-Z0-9]+/g, '_').replace(/^_|_$/g, '').toLowerCase();
}

